import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';

const Home = () => (
  <div className="py-20 text-center">
    <h1 className="text-5xl font-extrabold text-gray-900 mb-6">Welcome to EcommerceApp</h1>
    <p className="text-xl text-gray-500 mb-8 max-w-2xl mx-auto">
      Discover amazing products at unbeatable prices. Built with React and Spring Boot.
    </p>
  </div>
);

const Dashboard = () => (
  <div className="py-12 px-8 max-w-7xl mx-auto">
    <h1 className="text-4xl font-bold mb-6">Dashboard</h1>
    <p>Welcome back! Here are your recent orders.</p>
  </div>
);

function App() {
  return (
    <Router>
      <div className="font-sans min-h-screen flex flex-col bg-gray-50">
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/dashboard" element={<Dashboard />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;
